export const meta = {
  name: 'verify_nice_ionice_syscall',
  description: '验证 nice/ionice syscall 替换在 Linux 下的正确性——编译、测试、内核确认',
  phases: [{ title: '验证' }]
};

// 阶段1：编译验证
phase('验证');

// agent 1: 编译 executor 包
const buildResult = await agent(`
请验证以下内容并返回 JSON:
1. 运行 go vet ./internal/executor/ 确认无 vet 错误
2. 运行 go build -o /dev/null ./main.go 确认完整构建成功（注意 main redeclared 是已知问题，internal/* 编译通过即可）
3. 提取 go.mod 中的 Go 版本号

当前目录: /mnt/d/claudeprj/codex
使用 CGO_ENABLED=0

返回格式: {"vet_ok": bool, "build_ok": bool, "go_version": "x.xx"}
`, { label: 'build verify', tier: 'small' });

// agent 2: 运行全部 internal 测试
const testResult = await agent(`
运行所有 internal 包测试：

cd /mnt/d/claudeprj/codex && CGO_ENABLED=0 go test ./internal/... -count=1 -timeout 60s 2>&1

返回 JSON: {"total_pkgs": N, "failed_pkgs": 0, "detail": "每包结果"}
如果有任何 FAIL，必须如实报告。
`, { label: 'test verify', tier: 'small' });

// agent 3: 测试 setIONice 和 setpriority syscall 可用性（真实 WSL 内核）
const kernelResult = await agent(`
验证 shell_unix.go 中 setIONice 和 syscall.Setpriority 在 Linux 内核下的表现。

运行以下 Go 代码片段：

\`\`\`go
package main

import (
	"fmt"
	"os"
	"os/exec"
	"syscall"
	"strings"
)

func setIONice(pid int, class int) error {
	if class <= 0 || class > 3 { return nil }
	const IOPRIO_WHO_PROCESS = 1
	classBits := (class & 0x7) << 13
	_, _, err := syscall.Syscall(syscall.SYS_IOPRIO_SET, IOPRIO_WHO_PROCESS, uintptr(pid), uintptr(classBits))
	if err != 0 && err != syscall.EINVAL { return err }
	return nil
}

func main() {
	cmd := exec.Command("sh", "-c", "sleep 1; echo done")
	cmd.SysProcAttr = &syscall.SysProcAttr{Setpgid: true}
	cmd.Start()
	pid := cmd.Process.Pid

	// 1. setpriority
	e1 := syscall.Setpriority(syscall.PRIO_PROCESS, pid, 19)

	// 2. 读 /proc/pid/stat 验证
	stat, _ := os.ReadFile(fmt.Sprintf("/proc/%d/stat", pid))
	fields := strings.Fields(string(stat))
	niceVal := fields[18]

	// 3. setIONice
	e2 := setIONice(pid, 3)

	cmd.Wait()
	fmt.Printf("setpriority err=%v\\n", e1)
	fmt.Printf("proc nice=%s\\n", niceVal)
	fmt.Printf("setIONice err=%v\\n", e2)
}
\`\`\`

保存为 /tmp/verify_syscall.go 然后运行:
cd /mnt/d/claudeprj/codex && CGO_ENABLED=0 go run /tmp/verify_syscall.go

返回 JSON: {"setpriority_ok": bool, "proc_nice": "N", "setionice_ok": bool}
`, { label: 'kernel verify', tier: 'small' });

// 合成
const verdict = {
  build: buildResult,
  tests: testResult,
  kernel: kernelResult
};

log('build: ' + JSON.stringify(buildResult));
log('tests: ' + JSON.stringify(testResult));
log('kernel: ' + JSON.stringify(kernelResult));

return verdict;

